import psycopg2
from psycopg2 import pool
import os
from typing import Optional

def get_db_connection():
    """
    Create and return a PostgreSQL database connection.
    Credentials are loaded from environment variables with fallback defaults for development.
    """
    db_host = os.getenv('DB_HOST', 'localhost')
    db_port = os.getenv('DB_PORT', '5432')
    db_name = os.getenv('DB_NAME', 'hackathon_db')
    db_user = os.getenv('DB_USER', 'admin')
    db_password = os.getenv('DB_PASSWORD', 'demo123')
    
    try:
        connection = psycopg2.connect(
            host=db_host,
            port=db_port,
            database=db_name,
            user=db_user,
            password=db_password
        )
        return connection
    except psycopg2.Error as e:
        print(f"Error connecting to PostgreSQL database: {e}")
        raise


class DatabaseConnectionPool:
    """
    Connection pool manager for PostgreSQL database.
    """
    _instance: Optional[pool.SimpleConnectionPool] = None
    
    @classmethod
    def get_pool(cls, minconn=1, maxconn=10):
        """Get or create connection pool"""
        if cls._instance is None:
            db_host = os.getenv('DB_HOST', 'localhost')
            db_port = os.getenv('DB_PORT', '5432')
            db_name = os.getenv('DB_NAME', 'hackathon_db')
            db_user = os.getenv('DB_USER', 'admin')
            db_password = os.getenv('DB_PASSWORD', 'demo123')
            
            cls._instance = pool.SimpleConnectionPool(
                minconn,
                maxconn,
                host=db_host,
                port=db_port,
                database=db_name,
                user=db_user,
                password=db_password
            )
        return cls._instance
    
    @classmethod
    def get_connection(cls):
        """Get a connection from the pool"""
        pool_instance = cls.get_pool()
        return pool_instance.getconn()
    
    @classmethod
    def return_connection(cls, connection):
        """Return a connection to the pool"""
        pool_instance = cls.get_pool()
        pool_instance.putconn(connection)
    
    @classmethod
    def close_all(cls):
        """Close all connections in the pool"""
        if cls._instance is not None:
            cls._instance.closeall()
            cls._instance = None


def execute_query(query, params=None, fetch=True):
    """
    Execute a query and return results.
    """
    connection = get_db_connection()
    try:
        cursor = connection.cursor()
        cursor.execute(query, params)
        
        if fetch:
            results = cursor.fetchall()
            cursor.close()
            connection.close()
            return results
        else:
            connection.commit()
            cursor.close()
            connection.close()
            return None
    except Exception as e:
        connection.rollback()
        connection.close()
        print(f"Error executing query: {e}")
        raise